#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

#define SESSION_TIMEOUT 300
#define MAX_SESSIONS 100

typedef struct Session {
    char *session_id;
    char *data;
    time_t last_access;
    int is_active;
} Session;

Session cache[MAX_SESSIONS];

void init_cache() {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        cache[i].session_id = NULL;
        cache[i].data = NULL;
        cache[i].is_active = 0;
    }
}

Session* find_session(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache[i].session_id && strcmp(cache[i].session_id, session_id) == 0) {
            return &cache[i];
        }
    }
    return NULL;
}

Session* create_session(const char *session_id) {
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache[i].session_id == NULL || cache[i].is_active == 0) {
            if (cache[i].session_id == NULL) {
                cache[i].session_id = strdup(session_id);
            }
            cache[i].data = strdup("Initial Session Data");
            cache[i].last_access = time(NULL);
            cache[i].is_active = 1;
            return &cache[i];
        }
    }
    return NULL;
}

void access_session(const char *session_id) {
    Session *session = find_session(session_id);
    if (session && difftime(time(NULL), session->last_access) <= SESSION_TIMEOUT) {
        session->last_access = time(NULL);
        printf("Accessed session %s: %s\n", session_id, session->data);
    } else {
        printf("Session %s expired or not found.\n", session_id);
    }
}

void invalidate_session(const char *session_id) {
    Session *session = find_session(session_id);
    if (session) {
        session->is_active = 0;
        if (session->data) {
            free(session->data);
            session->data = NULL;
        }
    }
}

void cleanup_expired_sessions() {
    time_t now = time(NULL);
    for (int i = 0; i < MAX_SESSIONS; i++) {
        if (cache[i].is_active && difftime(now, cache[i].last_access) > SESSION_TIMEOUT) {
            invalidate_session(cache[i].session_id);
        }
    }
}

